s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
sns_client = boto3.client('sns')
sqs_client = boto3.client('sqs')

S3_BUCKET = os.environ.get('S3_BUCKET', 'microservices-data')
DYNAMODB_TABLE = os.environ.get('DYNAMODB_TABLE', 'microservices-events')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN', '')
SQS_QUEUE_URL = os.environ.get('SQS_QUEUE_URL', '')


def lambda_handler(event, context):
    try:
        event_id = context.request_id
        timestamp = datetime.utcnow().isoformat()
        
        table = dynamodb.Table(DYNAMODB_TABLE)
        
        event_data = {
            'eventId': event_id,
            'timestamp': timestamp,
            'functionName': context.function_name,
            'eventData': json.dumps(event),
            'status': 'processing'
        }
        
        table.put_item(Item=event_data)
        
        s3_key = f"events/{datetime.utcnow().strftime('%Y/%m/%d')}/{event_id}.json"
        s3_client.put_object(
            Bucket=S3_BUCKET,
            Key=s3_key,
            Body=json.dumps(event_data),
            ContentType='application/json'
        )
        
        if SNS_TOPIC_ARN:
            sns_client.publish(
                TopicArn=SNS_TOPIC_ARN,
                Message=json.dumps({
                    'eventId': event_id,
                    'functionName': context.function_name,
                    'timestamp': timestamp,
                    'status': 'processed'
                }),
                Subject=f'Event Processed: {event_id}'
            )
        
        if SQS_QUEUE_URL:
            sqs_client.send_message(
                QueueUrl=SQS_QUEUE_URL,
                MessageBody=json.dumps({
                    'eventId': event_id,
                    'functionName': context.function_name,
                    's3Location': f's3://{S3_BUCKET}/{s3_key}',
                    'timestamp': timestamp
                })
            )
        
        table.update_item(
            Key={'eventId': event_id},
            UpdateExpression='SET #status = :status',
            ExpressionAttributeNames={'#status': 'status'},
            ExpressionAttributeValues={':status': 'completed'}
        )
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Event processed successfully',
                'eventId': event_id,
                's3Location': f's3://{S3_BUCKET}/{s3_key}'
            })
        }
        
    except Exception as e:
        print(f"Error processing event: {str(e)}")
        
        if 'event_id' in locals():
            try:
                table.update_item(
                    Key={'eventId': event_id},
                    UpdateExpression='SET #status = :status, errorMessage = :error',
                    ExpressionAttributeNames={'#status': 'status'},
                    ExpressionAttributeValues={
                        ':status': 'failed',
                        ':error': str(e)
                    }
                )
            except:
                pass
        
        return {
            'statusCode': 500,
            'body': json.dumps({
                'message': 'Error processing event',
                'error': str(e)
            })
        }